class Solution {
public:
    bool digitCount(string num) {
        int count[10] = {0}; // Initialize an array to store the count of each digit
        for (char c : num) {
            count[c - '0']++; // Increment the count of each digit
        }
        for (int i = 0; i < num.length(); i++) {
            if (count[num[i] - '0'] != num.length()) {
                return false;
            }
            count[num[i] - '0']--; // Decrement the count of each digit
        }
        return true;
    }
};
```

